    edges.sort((a, b) => a[2] - b[2]);

    // Build adjacency list
    const adj: number[][] = new Array(n).fill(0).map(() => new Array<number>());

    for (const [u, v, w] of edges) {
        adj[u].push([v, w]);
        adj[v].push([u, w]);
    }

    // Union-Find data structure
    class UnionFind {
        parent: number[];
        rank: number[];

        constructor(size: number) {
            this.parent = new Array(size).fill(0).map((_, i) => i);
            this.rank = new Array(size).fill(0);
        }

        find(x: number): number {
            if (this.parent[x] !== x) {
                this.parent[x] = this.find(this.parent[x]);
            }
            return this.parent[x];
        }

        union(x: number, y: number): boolean {
            const xRoot = this.find(x);
            const yRoot = this.find(y);

            if (xRoot === yRoot) {
                return false;
            }

            if (this.rank[xRoot] < this.rank[yRoot]) {
                this.parent[xRoot] = yRoot;
            } else {
                this.parent[yRoot] = xRoot;
                if (this.rank[xRoot] === this.rank[yRoot]) {
                    this.rank[xRoot]++;
                }
            }
            return true;
        }
    }

    // Initialize Union-Find
    const uf = new UnionFind(n);

    // Keep track of the maximum edge weight in each component
    const maxEdgeInComponent: number[] = new Array(n).fill(0);

    // Process edges in increasing order of weight
    let result = 0;
    let components = n;

    for (const [u, v, w] of edges) {
        const rootU = uf.find(u);
        const rootV = uf.find(v);

        if (rootU !== rootV) {
            // Merge the components
            uf.union(rootU, rootV);

            // Update the max edge weight for the new component
            maxEdgeInComponent[uf.find(rootU)] = Math.max(maxEdgeInComponent[rootU], maxEdgeInComponent[rootV], w);

            // Decrease the number of components
            components--;
        }

        // Check if we have reached the desired number of components
        if (components === k) {
            result = Math.max(result, maxEdgeInComponent[uf.find(0)]);
            break;
        }
    }

    return result;
